#include<stdio.h>

int main()
{
    long long int i=0,n,count=0,temp,mod,M=1;
    scanf("%lld",&n);
    while(1)
    {
        // printf("%lld\n", i);
        M=M*2;
        mod=n%M;
        temp=n/M;
        // printf("%lld %lld %lld\n",temp , mod,M);
        if(mod>M/2)
            count+=(M/2)*(temp+1);
        else{
                count+=(M/2)*(temp);
            }
        if(temp<=0)
            break;
        i++;
    }
    printf("%lld\n", count);
    return 0;
}

